  # https://devenv.sh/tests/
  enterTest = ''
    echo "Running tests"
    node --version | grep --color=auto "${pkgs.nodejs.version}"
    pnpm --version | grep --color=auto "${pkgs.pnpm.version}"
  '';

  # https://devenv.sh/git-hooks/
