file.content:
:root {
  --mono: ui-monospace, "Cascadia Code", "Source Code Pro", Menlo, Consolas, "DejaVu Sans Mono", monospace;

  --bg: #fafafa;
  --fg: #1a1a1a;
  --accent: #0055cc;
  --muted: #666;
  --border: #e0e0e0;

  --pad: 2rem;
  --max-width: 64ch;
}

@media (prefers-color-scheme: dark) {
  :root {
    --bg: #0f0f0f;
    --fg: #e0e0e0;
    --accent: #4d9fff;
    --muted: #888;
    --border: #2a2a2a;
  }
}

*, *::before, *::after {
  box-sizing: border-box;
}

body {
  font-family: var(--mono);
  font-size: 0.9rem;
  line-height: 1.65;
  background: var(--bg);
  color: var(--fg);
  margin: 0;
}

a {
  color: var(--accent);
  text-decoration: none;
}

a:hover {
  text-decoration: underline;
}

h1, h2, h3 {
  font-size: 1rem;
  font-weight: bold;
  margin: 0 0 1rem;
}

p, ul, ol {
  margin: 0 0 0.75rem;
}

ul, ol {
  padding-left: 1.5rem;
}

code {
  background: var(--border);
  padding: 0.1em 0.35em;
  border-radius: 2px;
}

strong {
  font-weight: bold;
}

.app-shell {
  display: flex;
  flex-direction: column;
  min-height: 100dvh;
  background: var(--bg);
}

.topbar {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  height: 2.75rem;
  padding: 0 1rem;
  border-bottom: 1px solid var(--border);
  font-size: 0.85rem;
  font-family: var(--mono);
}

.back-link {
  color: var(--muted);
  text-decoration: none;
  font-size: 1.1rem;
}

.page {
  padding: var(--pad);
  max-width: var(--max-width);
}

.canvas-app {
  display: flex;
  flex-direction: column;
  height: 100dvh;
  background: var(--bg);
}

.canvas-stage {
  flex: 1;
  overflow: hidden;
  position: relative;
}

.toolbar-button {
  background: none;
  border: 1px solid var(--border);
  color: var(--muted);
  font-family: var(--mono);
  font-size: 0.85rem;
  padding: 0.1rem 0.6rem;
  cursor: pointer;
}

.control-label {
  display: flex;
  align-items: center;
  gap: 0.4rem;
  color: var(--fg);
}

